#!/usr/bin/env bash
set -euo pipefail

cd /workspace/prql

# Idempotency: skip if the gold change is already applied.
if grep -q "tiered testing approach" CLAUDE.md 2>/dev/null; then
    echo "Gold patch already applied; nothing to do."
    exit 0
fi

# Patch is base64-encoded so the verbatim ` ` context lines (single-space
# blank-context lines) and the en-dash byte sequence survive HEREDOC
# transcription. Decoded it is the unmodified `gh pr diff 5629` output
# from PRQL/prql; it is not fetched at run time — the bytes are inlined
# below.
PATCH_B64=''

echo "$PATCH_B64" | base64 -d | git apply --whitespace=nowarn -

echo "Gold patch applied."
